import sys

n = int(sys.stdin.readline())
a = list(map(int, sys.stdin.readline().split()))

odd = []
even = []
for i in a:
    if i % 2 == 0:
        even.append(i)
    else:
        odd.append(i)

odd.sort(reverse=True)
even.sort(reverse=True)

if len(odd) == 0:
    print(even[0])
elif len(even) == 0:
    print(odd[0])
else:
    if odd[0] > even[0]:
        print(odd[0])
    else:
        print(even[0])
